#include "verilated.h"

// INCLUDE MODEL CLASS

#include "Vtop.h"

// INCLUDE MODULE CLASSES
#include "Vtop___024root.h"

// DPI TYPES for DPI Export callbacks (Internal use)
using Vtop__Vcb_write_data_t = void (*) (Vtop__Syms* __restrict vlSymsp, CData/*2:0*/ iA, IData/*31:0*/ iD);
using Vtop__Vcb_write_data_t = void (*) (Vtop__Syms* __restrict vlSymsp, CData/*2:0*/ iA, VlWide<4>/*127:0*/ iD);

// SYMS CLASS (contains all model state)
class Vtop__Syms final : public VerilatedSyms {
  public:
    // INTERNAL STATE
    Vtop* const __Vm_modelp;
    bool __Vm_didInit = false;

    // MODULE INSTANCE STATE
    Vtop___024root                 TOP;

    // SCOPE NAMES
    VerilatedScope __Vscope_top__u_sub1;
    VerilatedScope __Vscope_top__u_sub2;

    // CONSTRUCTORS
    Vtop__Syms(VerilatedContext* contextp, const char* namep, Vtop* modelp);
    ~Vtop__Syms();

    // METHODS
    const char* name() { return TOP.name(); }
} VL_ATTR_ALIGNED(VL_CACHE_LINE_BYTES);

#endif  // guard

```

The compile error is as follows:
```log
Vtop__Syms.h:21:7: error: conflicting declaration ‘using Vtop__Vcb_write_data_t = void (*)(class Vtop__Syms*, using CData = uint8_t, struct VlWide<4>)’
